import{_ as a,o as t,c as s,ag as n}from"./chunks/framework.BY_YGHoI.js";const u=JSON.parse('{"title":"Types","description":"","frontmatter":{},"headers":[],"relativePath":"reference/types.md","filePath":"reference/types.md"}'),o={name:"reference/types.md"};function i(d,e,p,c,l,r){return t(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h1><p>MLang is statically typed. Every variable has a known type at declaration time.</p><h2 id="primitive-types" tabindex="-1">Primitive types <a class="header-anchor" href="#primitive-types" aria-label="Permalink to &quot;Primitive types&quot;">​</a></h2><h3 id="int" tabindex="-1"><code>int</code> <a class="header-anchor" href="#int" aria-label="Permalink to &quot;`int`&quot;">​</a></h3><p>64-bit signed integer.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>int x = 42;</span></span>\n<span class="line"><span>int neg = -7;</span></span></code></pre></div><p>Arithmetic: <code>+</code> <code>-</code> <code>*</code> <code>/</code> (integer division, truncates toward zero).</p><h3 id="dec" tabindex="-1"><code>dec</code> <a class="header-anchor" href="#dec" aria-label="Permalink to &quot;`dec`&quot;">​</a></h3><p>64-bit IEEE 754 floating-point.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dec pi = 3.14159;</span></span>\n<span class="line"><span>dec ratio = 1.0 / 3.0;</span></span></code></pre></div><p>Mixed <code>int</code>/<code>dec</code> arithmetic promotes to <code>dec</code>:</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dec result = 2 + 0.5;   # 2.5</span></span></code></pre></div><h3 id="txt" tabindex="-1"><code>txt</code> <a class="header-anchor" href="#txt" aria-label="Permalink to &quot;`txt`&quot;">​</a></h3><p>UTF-8 string.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>txt greeting = &quot;Hello, world!&quot;;</span></span></code></pre></div><p>Concatenation with <code>+</code>:</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>txt full = &quot;Hello, &quot; + name;</span></span>\n<span class="line"><span>txt mixed = &quot;Score: &quot; + 100;   # coerces int to txt</span></span></code></pre></div><h3 id="bool" tabindex="-1"><code>bool</code> <a class="header-anchor" href="#bool" aria-label="Permalink to &quot;`bool`&quot;">​</a></h3><p><code>true</code> or <code>false</code>.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>bool active = true;</span></span>\n<span class="line"><span>bool done   = false;</span></span></code></pre></div><p>Logical operators: <code>&amp;&amp;</code> <code>||</code> <code>!</code></p><h2 id="composite-types" tabindex="-1">Composite types <a class="header-anchor" href="#composite-types" aria-label="Permalink to &quot;Composite types&quot;">​</a></h2><h3 id="array-t" tabindex="-1"><code>array&lt;T&gt;</code> <a class="header-anchor" href="#array-t" aria-label="Permalink to &quot;`array&lt;T&gt;`&quot;">​</a></h3><p>Ordered, homogeneous, dynamically sized.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>array&lt;int&gt; scores = [10, 20, 30];</span></span>\n<span class="line"><span>array&lt;txt&gt; tags   = [&quot;rust&quot;, &quot;lang&quot;];</span></span></code></pre></div><p><strong>Methods:</strong></p><table tabindex="0"><thead><tr><th>Method</th><th>Returns</th><th>Description</th></tr></thead><tbody><tr><td><code>a.len()</code></td><td><code>int</code></td><td>Number of elements</td></tr><tr><td><code>a.push(v)</code></td><td><code>int</code></td><td>Appends value, returns new len</td></tr><tr><td><code>a.pop()</code></td><td><code>T</code></td><td>Removes and returns last element</td></tr><tr><td><code>a.clear()</code></td><td><code>int</code></td><td>Empties array, returns 0</td></tr><tr><td><code>a.contains(v)</code></td><td><code>bool</code></td><td>Membership test</td></tr><tr><td><code>a.slice(start, end)</code></td><td><code>array&lt;T&gt;</code></td><td>Sub-array (exclusive end)</td></tr></tbody></table><p>Index access and assignment:</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>print(scores[0]);    # 10</span></span>\n<span class="line"><span>scores[1] = 99;</span></span></code></pre></div><h3 id="struct" tabindex="-1"><code>struct</code> <a class="header-anchor" href="#struct" aria-label="Permalink to &quot;`struct`&quot;">​</a></h3><p>Named collection of typed fields. See <a href="./structs.html">Structs</a> for full details.</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>struct Point { int x; int y }</span></span>\n<span class="line"><span>let p = Point { x = 3, y = 7 };</span></span>\n<span class="line"><span>print(p.x);</span></span></code></pre></div><h2 id="type-conversions" tabindex="-1">Type conversions <a class="header-anchor" href="#type-conversions" aria-label="Permalink to &quot;Type conversions&quot;">​</a></h2><p>Explicit casts using built-in functions:</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>int n   = int(&quot;42&quot;);      # parse txt → int</span></span>\n<span class="line"><span>dec d   = dec(n);         # widen int → dec</span></span>\n<span class="line"><span>int i   = int(3.9);       # truncate dec → int  (= 3)</span></span>\n<span class="line"><span>txt s   = txt(100);       # format int → txt</span></span></code></pre></div><p><code>read()</code> always returns <code>txt</code>; use <code>int()</code> / <code>dec()</code> to parse user input:</p><div class="language-mlang vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mlang</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>int age = int(read(&quot;Age: &quot;));</span></span></code></pre></div>',37)])])}const g=a(o,[["render",i]]);export{u as __pageData,g as default};
